$r = Get-Content compare_report_auto.json -Raw | ConvertFrom-Json
function RD($s){ if(-not $s){ return '' }; $sb = New-Object System.Text.StringBuilder; $norm = $s.Normalize([System.Text.NormalizationForm]::FormD); foreach($c in $norm.ToCharArray()){ if([Globalization.CharUnicodeInfo]::GetUnicodeCategory($c) -ne [Globalization.UnicodeCategory]::NonSpacingMark){ $null=$sb.Append($c) } } return $sb.ToString().Normalize([System.Text.NormalizationForm]::FormC) }
foreach($d in $r.details){ $exp=$d.expected; $act=$d.actual; $actNorm=RD($act.ToString().ToLower()); $expNorm=RD($exp.ToString().ToLower()); $actAscii = ($actNorm -replace '[^a-z0-9]',''); $expAscii = ($expNorm -replace '[^a-z0-9]',''); Write-Output ($d.contract + " | expected:'" + $exp + "' | actual:'" + $act + "' | actNorm:'" + $actNorm + "' | expNorm:'" + $expNorm + "' | actAscii:'" + $actAscii + "' | expAscii:'" + $expAscii + "'") }
